import React, { useState, useEffect } from "react";

const Profile = () => {
  const userId = localStorage.getItem("userId");

  const [image, setImage] = useState("");
  const [name, setName] = useState("");
  const [bio, setBio] = useState("");

  // Load user-specific data
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
    setImage(data.image || "");
    setName(data.name || "");
    setBio(data.bio || "");
  }, [userId]);

  // Upload Image
  const handleImage = (e) => {
    const file = e.target.files[0];
    const reader = new FileReader();

    reader.onloadend = () => {
      setImage(reader.result);
    };

    if (file) reader.readAsDataURL(file);
  };

  // Save Profile
  const handleSave = () => {
    const data = { image, name, bio };
    localStorage.setItem(`profile_${userId}`, JSON.stringify(data));
    alert("Profile Saved ✅");
  };

  return (
    <div style={container}>
      <h2>My Profile</h2>

      {/* Image */}
      <div>
        <img
          src={image || "https://via.placeholder.com/150"}
          alt="profile"
          style={imgStyle}
        />
      </div>

      <input type="file" onChange={handleImage} style={inputFile} />

      {/* Name */}
      <input
        type="text"
        placeholder="Enter your name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        style={input}
      />

      {/* Bio */}
      <textarea
        placeholder="Write your bio..."
        value={bio}
        onChange={(e) => setBio(e.target.value)}
        style={textarea}
      />

      <button onClick={handleSave} style={btn}>
        Save Profile
      </button>
    </div>
  );
};

// 🎨 Styles
const container = {
  maxWidth: "400px",
  margin: "50px auto",
  padding: "30px",
  borderRadius: "10px",
  boxShadow: "0 0 10px rgba(0,0,0,0.1)",
  textAlign: "center",
  background: "#fff",
};

const imgStyle = {
  width: "120px",
  height: "120px",
  borderRadius: "50%",
  objectFit: "cover",
  marginBottom: "15px",
};

const inputFile = {
  marginBottom: "15px",
};

const input = {
  width: "100%",
  padding: "10px",
  marginBottom: "10px",
};

const textarea = {
  width: "100%",
  height: "80px",
  padding: "10px",
  marginBottom: "10px",
};

const btn = {
  padding: "10px 20px",
  background: "#ff6b6b",
  color: "#fff",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer",
};

export default Profile;
